CREATE TABLE gdpr_article_to_question
(
	id serial,
	organization_id integer NOT NULL,
	article_id integer DEFAULT NULL,
	paragraph_id integer DEFAULT NULL,
	question_id integer DEFAULT NULL,
	CONSTRAINT pk_gdpr_article_to_question PRIMARY KEY (id)
	, CONSTRAINT fk_gdpr_article_to_question_to_article FOREIGN KEY (article_id) REFERENCES gdpr_article (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
	, CONSTRAINT fk_gdpr_article_to_question_to_question FOREIGN KEY (question_id) REFERENCES qualitative_questions (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
	, CONSTRAINT fk_gdpr_article_to_question_to_organization FOREIGN KEY (organization_id) REFERENCES organizations (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
);
CREATE INDEX i_gdpr_article_to_question_article ON gdpr_article_to_question (article_id);
CREATE INDEX i_gdpr_article_to_question_organization ON gdpr_article_to_question (organization_id);
CREATE INDEX i_gdpr_article_to_question_question ON gdpr_article_to_question (question_id);
